import math

def solve(nums: list[int]) -> int:
    # Function to check if a number is prime
    def is_prime(n: int) -> bool:
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(math.sqrt(n)) + 1, 2):
            if n % i == 0:
                return False
        return True

    sum_a = 0
    sum_b = 0

    for i in range(len(nums)):
        if is_prime(i):
            sum_a += nums[i]
        else:
            sum_b += nums[i]

    return abs(sum_a - sum_b)
